-- Totalen bijwerken
UPDATE statements SET
  total_royalties = (SELECT COALESCE(SUM(nett_royalty),0) FROM statement_lines WHERE statement_id = statements.id),
  line_count = (SELECT COUNT(*) FROM statement_lines WHERE statement_id = statements.id);